SELECT COUNT(*) AS active_default_values_count
FROM defaults
WHERE is_active = 1;

SELECT COUNT(*) AS total_validations
FROM validations
WHERE is_active = 1;

SELECT name, LOG2(data_type_id) AS log_data_type_id
FROM data_types
WHERE data_type_id > 0;

SELECT comment 
FROM data_types 
WHERE data_type_id = 1;

SELECT COUNT(*) AS active_validation_rules
FROM validation_rules
WHERE data_type_id = (SELECT data_type_id FROM data_types WHERE name = 'string') AND is_active = 1;
